.mrg-code-block {
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
  border-block-start-color: var(--mrg-semantic-color-brand-living);
  border-block-start-width: var(--mrg-semantic-border-width-strong);
  border-radius: var(--mrg-semantic-radius-panel);
  color: var(--mrg-semantic-color-foreground-primary);
  font-family: var(--mrg-semantic-font-family-machine);
  font-size: var(--mrg-semantic-font-size-code);
  line-height: var(--mrg-semantic-font-line-height-code);
  max-inline-size: 100%;
  min-inline-size: 0;
}
.mrg-code-block-header {
  align-items: center;
  border-block-end: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-strong);
  display: flex;
  flex-wrap: wrap;
  gap: var(--mrg-semantic-space-inline-sm);
  justify-content: flex-end;
  padding: var(--mrg-semantic-space-inline-sm);
  background: var(--mrg-semantic-color-background-surface);
}
.mrg-code-block [data-slot="code-block-title"] {
  font-weight: var(--mrg-semantic-font-weight-code);
  margin-inline-end: auto;
  overflow-wrap: anywhere;
}
.mrg-code-block [data-slot="code-block-language"] {
  color: var(--mrg-semantic-color-brand-violet);
}
.mrg-code-block [data-slot="code-block-copy"] {
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-default) solid currentColor;
  border-radius: var(--mrg-semantic-radius-control);
  color: inherit;
  font: inherit;
  min-block-size: var(--mrg-semantic-size-target-minimum);
  padding-block: var(--mrg-semantic-space-inline-xs);
  padding-inline: var(--mrg-semantic-space-inline-sm);
  transition:
    background var(--mrg-semantic-motion-duration-feedback)
      var(--mrg-semantic-motion-easing-standard),
    color var(--mrg-semantic-motion-duration-feedback) var(--mrg-semantic-motion-easing-standard);
}
.mrg-code-block [data-slot="code-block-copy"]:hover {
  background: var(--mrg-semantic-color-background-surface-sunken);
}
.mrg-code-block [data-slot="code-block-copy"][data-copy-status="copied"] {
  background: var(--mrg-semantic-color-selection-background);
  color: var(--mrg-semantic-color-selection-foreground);
}
.mrg-code-block [data-slot="code-block-copy"][data-copy-status="error"] {
  background: var(--mrg-semantic-color-status-danger-background);
  color: var(--mrg-semantic-color-status-danger-foreground);
}
.mrg-code-block [data-slot="code-block-copy"]:focus-visible,
.mrg-code-block [data-slot="code-block-scroll"]:focus-visible {
  box-shadow: 0 0 0 var(--mrg-semantic-border-width-default)
    var(--mrg-component-focus-indicator-contrast-background);
  outline: var(--mrg-component-focus-indicator-width) solid
    var(--mrg-component-focus-indicator-color);
  outline-offset: var(--mrg-component-focus-indicator-offset);
}
.mrg-code-block [data-slot="code-block-scroll"] {
  margin: 0;
  max-block-size: 32rem;
  max-inline-size: 100%;
  overflow: auto;
  padding-block: var(--mrg-semantic-space-inline-md);
  tab-size: 2;
}
.mrg-code-block [data-slot="code-block-code"] {
  display: block;
  min-inline-size: max-content;
}
.mrg-code-block[data-wrap="true"] [data-slot="code-block-code"] {
  min-inline-size: 0;
}
.mrg-code-block [data-slot="code-block-line"] {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  min-inline-size: 100%;
}
.mrg-code-block [data-slot="code-block-line-number"] {
  border-inline-end: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-strong);
  color: var(--mrg-semantic-color-foreground-muted);
  min-inline-size: 3.5em;
  padding-inline: var(--mrg-semantic-space-inline-md);
  text-align: end;
  user-select: none;
}
.mrg-code-block [data-slot="code-block-line-content"] {
  padding-inline: var(--mrg-semantic-space-inline-md);
}
.mrg-code-block[data-wrap="true"] [data-slot="code-block-line-content"] {
  overflow-wrap: anywhere;
  white-space: break-spaces;
}
.mrg-code-block [data-highlighted="true"] {
  background: var(--mrg-semantic-color-selection-background);
  color: var(--mrg-semantic-color-selection-foreground);
  font-weight: var(--mrg-semantic-font-weight-strong);
  outline: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-selection-border);
  outline-offset: calc(var(--mrg-semantic-border-width-default) * -1);
}
.mrg-code-block-sr-only {
  block-size: 1px;
  clip: rect(0 0 0 0);
  clip-path: inset(50%);
  inline-size: 1px;
  overflow: hidden;
  position: absolute;
  white-space: nowrap;
}
@media (forced-colors: active) {
  .mrg-code-block {
    background: Canvas;
    border-color: CanvasText;
    color: CanvasText;
  }
  .mrg-code-block-header,
  .mrg-code-block [data-slot="code-block-line-number"] {
    border-color: CanvasText;
  }
  .mrg-code-block [data-highlighted="true"] {
    background: Highlight;
    color: HighlightText;
    outline-color: Highlight;
  }
  .mrg-code-block [data-slot="code-block-copy"]:focus-visible,
  .mrg-code-block [data-slot="code-block-scroll"]:focus-visible {
    box-shadow: none;
    outline-color: Highlight;
  }
}
@media (prefers-reduced-motion: reduce) {
  .mrg-code-block * {
    scroll-behavior: auto;
  }

  .mrg-code-block [data-slot="code-block-copy"] {
    transition-duration: var(--mrg-semantic-motion-duration-reduced);
  }
}

"use client";

import { forwardRef, useId, useState, type HTMLAttributes, type ReactNode } from "react";

import { useMergoraMessage } from "../provider/index";
import "./code-block.css";

export type CodeBlockStatus = "idle" | "copied" | "error";

export interface CodeBlockProps extends Omit<HTMLAttributes<HTMLDivElement>, "children"> {
  /** Exact source text rendered line by line and written by the optional copy action. */
  readonly code: string;
  /** Localized status announced after a successful clipboard write. */
  readonly copiedLabel?: string;
  /** Adds the clipboard action and its private live status when enabled. */
  readonly copyable?: boolean;
  /** Localized status announced when the clipboard write fails. */
  readonly copyErrorLabel?: string;
  /** Localized accessible label for the clipboard action. */
  readonly copyLabel?: string;
  /** Optional visible filename shown in place of the region label. */
  readonly filename?: string;
  /** One-based line numbers receiving a visible and screen-reader highlight cue. */
  readonly highlightedLines?: readonly number[];
  /** Accessible name for the code region and source viewport. */
  readonly label: string;
  /** Optional language identifier displayed as source context. */
  readonly language?: string;
  /** Called only after the exact source text is written successfully. */
  readonly onCopyComplete?: (code: string) => void;
  /** Replaces each line's visual content without changing copy-source bytes or numbering. */
  readonly renderLine?: (line: string, lineNumber: number) => ReactNode;
  /** Shows aria-hidden one-based line numbers alongside source lines. */
  readonly showLineNumbers?: boolean;
  /** Wraps long source lines; false keeps a keyboard-scrollable horizontal viewport. */
  readonly wrap?: boolean;
}

export function codeBlockLines(code: string): readonly string[] {
  return code.replaceAll("\r\n", "\n").replaceAll("\r", "\n").split("\n");
}

export async function writeCodeBlockClipboard(value: string): Promise<void> {
  if (typeof navigator !== "undefined" && navigator.clipboard !== undefined) {
    await navigator.clipboard.writeText(value);
    return;
  }
  if (typeof document === "undefined") throw new Error("Clipboard is unavailable.");
  const textarea = document.createElement("textarea");
  textarea.value = value;
  textarea.setAttribute("readonly", "");
  textarea.style.position = "fixed";
  textarea.style.insetInlineStart = "-10000px";
  document.body.append(textarea);
  try {
    textarea.select();
    const copied = document.execCommand("copy");
    if (!copied) throw new Error("Clipboard copy was rejected.");
  } finally {
    textarea.remove();
  }
}

export const CodeBlock = forwardRef<HTMLDivElement, CodeBlockProps>(function CodeBlock(
  {
    className,
    code,
    copiedLabel: copiedLabelProp,
    copyable = true,
    copyErrorLabel: copyErrorLabelProp,
    copyLabel: copyLabelProp,
    filename,
    highlightedLines = [],
    label,
    language,
    onCopyComplete,
    renderLine,
    showLineNumbers = true,
    wrap = false,
    ...nativeProps
  },
  forwardedRef,
) {
  const [status, setStatus] = useState<CodeBlockStatus>("idle");
  const statusId = useId();
  const lines = codeBlockLines(code);
  const highlighted = new Set(highlightedLines);
  const defaultCopiedLabel = useMergoraMessage("codeBlock.copied", "Copied");
  const defaultCopyErrorLabel = useMergoraMessage("codeBlock.copyError", "Copy failed");
  const defaultCopyLabel = useMergoraMessage("codeBlock.copy", "Copy code");
  const sourceLabel = useMergoraMessage("codeBlock.source", "{label} source", { label });
  const highlightedLabel = useMergoraMessage("codeBlock.highlighted", "Highlighted: ");
  const copiedLabel = copiedLabelProp ?? defaultCopiedLabel;
  const copyErrorLabel = copyErrorLabelProp ?? defaultCopyErrorLabel;
  const copyLabel = copyLabelProp ?? defaultCopyLabel;

  const copy = async (): Promise<void> => {
    try {
      await writeCodeBlockClipboard(code);
      setStatus("copied");
      onCopyComplete?.(code);
    } catch {
      setStatus("error");
    }
  };

  return (
    <div
      {...nativeProps}
      ref={forwardedRef}
      aria-label={label}
      className={
        className === undefined || className.trim().length === 0
          ? "mrg-code-block"
          : `mrg-code-block ${className}`
      }
      data-copyable={copyable ? "true" : "false"}
      data-slot="code-block"
      data-wrap={wrap ? "true" : "false"}
      role="region"
    >
      <div className="mrg-code-block-header" data-slot="code-block-header">
        <span data-slot="code-block-title">{filename ?? label}</span>
        {language === undefined ? null : <span data-slot="code-block-language">{language}</span>}
        {copyable ? (
          <button
            aria-describedby={statusId}
            data-copy-status={status}
            data-slot="code-block-copy"
            onClick={() => void copy()}
            type="button"
          >
            {status === "copied" ? copiedLabel : copyLabel}
          </button>
        ) : null}
      </div>
      <pre aria-label={sourceLabel} data-slot="code-block-scroll" tabIndex={0}>
        <code data-slot="code-block-code">
          {lines.map((line, index) => {
            const lineNumber = index + 1;
            const isHighlighted = highlighted.has(lineNumber);
            return (
              <span
                data-highlighted={isHighlighted ? "true" : "false"}
                data-line={String(lineNumber)}
                data-slot="code-block-line"
                key={lineNumber}
              >
                {showLineNumbers ? (
                  <span aria-hidden="true" data-slot="code-block-line-number">
                    {lineNumber}
                  </span>
                ) : null}
                {isHighlighted ? (
                  <span className="mrg-code-block-sr-only">{highlightedLabel}</span>
                ) : null}
                <span data-slot="code-block-line-content">
                  {renderLine?.(line, lineNumber) ?? line}
                </span>
                {index === lines.length - 1 ? null : "\n"}
              </span>
            );
          })}
        </code>
      </pre>
      {copyable ? (
        <span className="mrg-code-block-sr-only" id={statusId} role="status">
          {status === "copied" ? copiedLabel : status === "error" ? copyErrorLabel : ""}
        </span>
      ) : null}
    </div>
  );
});

CodeBlock.displayName = "CodeBlock";
